        // when - 첫 번째 호출 (캐시 미스 → DB 조회)
        profileService.getProfile(userId)
        // when - 두 번째 호출 (캐시 히트 → DB 조회 없어야 함)
        profileService.getProfile(userId)

        // then - DB는 정확히 1번만 호출되어야 함
        verify(profileRepository, times(1)).findByUserId(userId)
    }

    @Test
    fun `should evict cache when profile is updated`() {
        // given
        val userId = "user-123"
        val updateRequest = UpdateProfileRequest(nickname = "새닉네임")

        // when
        profileService.updateProfile(userId, updateRequest)

        // then - 캐시 무효화 확인
        val cache = cacheManager.getCache(CacheNames.USER_PROFILE)
        assertThat(cache?.get(userId)).isNull()
    }

    @Test
    fun `should return follow count from cache`() {
        // given
        val userId = "user-123"
        `when`(profileRepository.countFollowerByUserId(userId)).thenReturn(100L)

        // when
        val first  = profileService.getFollowCount(userId)
        val second = profileService.getFollowCount(userId)

        // then
        assertThat(first).isEqualTo(second)
        verify(profileRepository, times(1)).countFollowerByUserId(userId)
    }
}
