// 통화방 실시간 상태 - TTL이 동적이고 원자적 연산 필요한 경우
@Service
class CallService(
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    private val activeCallKey = "call:active:"

    // @Cacheable로 처리하기 어려운 원자적 연산
    fun joinCall(callRoomId: String, userId: String): Boolean {
        val key = "$activeCallKey$callRoomId"
        val ops = redisTemplate.opsForSet()
        ops.add(key, userId)
        redisTemplate.expire(key, Duration.ofHours(2))  // 통화 최대 2시간
        return true
    }

    fun getActiveParticipants(callRoomId: String): Set<Any> =
        redisTemplate.opsForSet().members("$activeCallKey$callRoomId") ?: emptySet()

    fun leaveCall(callRoomId: String, userId: String) {
        redisTemplate.opsForSet().remove("$activeCallKey$callRoomId", userId)
    }
}
